//测试回个人主页()
function 测试回个人主页() {
    var 最大尝试次数 = 600;
    var 开始时间 = new Date().getTime();

    for (var i = 0; i < 最大尝试次数; i++) {
        // 检查是否在评论区
        var 评论区 = className("android.widget.TextView").text("获赞").visibleToUser(true).findOnce();

        if (评论区) {
            var 耗时 = ((new Date().getTime() - 开始时间) / 1000).toFixed(1);
            console.log("✓ 已返个人主页 (耗时: " + 耗时 + "秒)");

            sleep(2000);
            return true;
        }

        // 不在评论区，执行返回操作
        // back();
        console.log("不在主页，执行返回 " + (i + 1) + "/" + 最大尝试次数);
        sleep(2000);
    }

    // 尝试了多次仍无法返回评论区
    console.log("× 无法返回个人主页(已尝试 " + 最大尝试次数 + " 次)");
    return false;
};

